     5→//! Wrap command - mark a pace complete with automated commit
     6→//!
     7→//! Stages all changes, generates a commit message with Claude,
     8→//! and transitions the pace state to complete with chalk marker.
     9→
    10→use std::path::PathBuf;
    11→use std::process::Command;
    12→use std::io::Write;
    13→
    14→use crate::jjrf_favor::{jjrf_Coronet as Coronet};
    15→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_TallyArgs as LibTallyArgs, jjrg_PaceState};
    16→use crate::jjrn_notch::{jjrn_ChalkMarker, jjrn_format_notch_prefix, jjrn_format_chalk_message};
    17→
    18→/// Arguments for jjx_wrap command
    19→#[derive(clap::Args, Debug)]
    20→pub struct jjrx_WrapArgs {
    21→    /// Pace identity (Coronet)
    22→    pub coronet: String,
    23→
    24→    /// Size limit in bytes (overrides default 50KB guard)
    25→    #[arg(long)]
    26→    pub size_limit: Option<u64>,
    27→}
    28→
    29→/// Execute wrap command - mark pace complete with commit
    30→///
    31→/// Stages all changes, checks size, generates commit message using Claude,
    32→/// creates the work commit, then transitions pace to complete state with
    33→/// chalk marker commit.
    34→///
    35→/// Returns exit code (0 for success, non-zero for failure).
    36→pub fn zjjrx_run_wrap(args: jjrx_WrapArgs) -> i32 {
    37→    // Parse coronet
    38→    let coronet = match Coronet::jjrf_parse(&args.coronet) {
    39→        Ok(c) => c,
    40→        Err(e) => {
    41→            eprintln!("jjx_wrap: error: {}", e);
    42→            return 1;
    43→        }
    44→    };
    45→
    46→    // Acquire commit lock
    47→    let _lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
    48→        Ok(l) => l,
    49→        Err(e) => {
    50→            eprintln!("jjx_wrap: error: {}", e);
    51→            return 1;
    52→        }
    53→    };
    54→
    55→    // Stage all changes
    56→    let add_output = match Command::new("git")
    57→        .args(["add", "-A"])
    58→        .output()
    59→    {
    60→        Ok(o) => o,
    61→        Err(e) => {
    62→            eprintln!("jjx_wrap: error: failed to run git add: {}", e);
    63→            return 1;
    64→        }
    65→    };
    66→
    67→    if !add_output.status.success() {
    68→        eprintln!("jjx_wrap: error: git add failed");
    69→        return 1;
    70→    }
    71→
    72→    // Size guard check
    73→    let size_limit = args.size_limit.unwrap_or(50000); // 50KB default
    74→    let diff_output = match Command::new("git")
    75→        .args(["diff", "--cached", "--stat"])
    76→        .output()
    77→    {
    78→        Ok(o) => o,
    79→        Err(e) => {
    80→            eprintln!("jjx_wrap: error: failed to run git diff: {}", e);
    81→            return 1;
    82→        }
    83→    };
    84→
    85→    if !diff_output.status.success() {
    86→        eprintln!("jjx_wrap: error: git diff failed");
    87→        return 1;
    88→    }
    89→
    90→    // Parse size from last line of --stat output (format: "N files changed, M insertions(+), K deletions(-)")
    91→    // Better size check: get actual staged content size
    92→    let numstat_output = match Command::new("git")
    93→        .args(["diff", "--cached", "--numstat"])
    94→        .output()
    95→    {
    96→        Ok(o) => o,
    97→        Err(e) => {
    98→            eprintln!("jjx_wrap: error: failed to run git diff --numstat: {}", e);
    99→            return 1;
   100→        }
   101→    };
   102→
   103→    if !numstat_output.status.success() {
   104→        eprintln!("jjx_wrap: error: git diff --numstat failed");
   105→        return 1;
   106→    }
   107→
   108→    let numstat_str = String::from_utf8_lossy(&numstat_output.stdout);
   109→    let mut total_size: u64 = 0;
   110→    for line in numstat_str.lines() {
   111→        let parts: Vec<&str> = line.split_whitespace().collect();
   112→        if parts.len() >= 2 {
   113→            // Format: added\tdeleted\tfilename
   114→            if let Ok(added) = parts[0].parse::<u64>() {
   115→                total_size += added;
   116→            }
   117→            if let Ok(deleted) = parts[1].parse::<u64>() {
   118→                total_size += deleted;
   119→            }
   120→        }
   121→    }
   122→
   123→    if total_size > size_limit {
   124→        eprintln!("jjx_wrap: error: staged changes exceed size limit ({} > {} bytes)", total_size, size_limit);
   125→        // Lock released automatically by Drop
   126→        return 2;
   127→    }
   128→
   129→    // Check if there are staged changes to commit
   130→    let has_staged_changes = !numstat_str.trim().is_empty();
   131→
   132→    // Only generate commit message and commit if there are staged changes
   133→    let commit_hash = if has_staged_changes {
   134→        // Generate commit message using Claude CLI
   135→        let diff_content = match Command::new("git")
   136→            .args(["diff", "--cached"])
   137→            .output()
   138→        {
   139→            Ok(o) => o,
   140→            Err(e) => {
   141→                eprintln!("jjx_wrap: error: failed to run git diff --cached: {}", e);
   142→                return 1;
   143→            }
   144→        };
   145→
   146→        if !diff_content.status.success() {
   147→            eprintln!("jjx_wrap: error: git diff --cached failed");
   148→            return 1;
   149→        }
   150→
   151→        let mut claude_cmd = match Command::new("claude")
   152→            .args([
   153→                "--print",
   154→                &format!("Generate a concise commit message for this diff. The commit wraps pace {}. Output only the message, no quotes.", args.coronet)
   155→            ])
   156→            .stdin(std::process::Stdio::piped())
   157→            .stdout(std::process::Stdio::piped())
   158→            .stderr(std::process::Stdio::piped())
   159→            .spawn()
   160→        {
   161→            Ok(c) => c,
   162→            Err(e) => {
   163→                eprintln!("jjx_wrap: error: failed to spawn claude command: {}", e);
   164→                return 1;
   165→            }
   166→        };
   167→
   168→        // Write diff to stdin
   169→        if let Some(mut stdin) = claude_cmd.stdin.take() {
   170→            if let Err(e) = stdin.write_all(&diff_content.stdout) {
   171→                eprintln!("jjx_wrap: error: failed to write to claude stdin: {}", e);
   172→                return 1;
   173→            }
   174→        }
   175→
   176→        let claude_output = match claude_cmd.wait_with_output() {
   177→            Ok(o) => o,
   178→            Err(e) => {
   179→                eprintln!("jjx_wrap: error: failed to wait for claude: {}", e);
   180→                return 1;
   181→            }
   182→        };
   183→
   184→        if !claude_output.status.success() {
   185→            eprintln!("jjx_wrap: error: claude command failed");
   186→            eprintln!("{}", String::from_utf8_lossy(&claude_output.stderr));
   187→            return 1;
   188→        }
   189→
   190→        let generated_message = String::from_utf8_lossy(&claude_output.stdout).trim().to_string();
   191→
   192→        // Commit with git directly (already staged via git add -A)
   193→        let prefix = jjrn_format_notch_prefix(&coronet);
   194→        let full_message = format!("{}{}\n\nCo-Authored-By: Claude <noreply@anthropic.com>", prefix, generated_message);
   195→
   196→        let commit_output = match Command::new("git")
   197→            .args(["commit", "-m", &full_message])
   198→            .output()
   199→        {
   200→            Ok(o) => o,
   201→            Err(e) => {
   202→                eprintln!("jjx_wrap: error: failed to run git commit: {}", e);
   203→                return 1;
   204→            }
   205→        };
   206→
   207→        if !commit_output.status.success() {
   208→            eprintln!("jjx_wrap: error: git commit failed");
   209→            eprintln!("{}", String::from_utf8_lossy(&commit_output.stderr));
   210→            return 1;
   211→        }
   212→
   213→        // Get commit hash
   214→        let hash_output = match Command::new("git")
   215→            .args(["rev-parse", "HEAD"])
   216→            .output()
   217→        {
   218→            Ok(o) => o,
   219→            Err(e) => {
   220→                eprintln!("jjx_wrap: error: failed to get commit hash: {}", e);
   221→                return 1;
   222→            }
   223→        };
   224→
   225→        String::from_utf8_lossy(&hash_output.stdout).trim().to_string()
   226→    } else {
   227→        // No staged changes - this is valid for verification-only paces
   228→        eprintln!("jjx_wrap: no staged changes, proceeding with state transition only");
   229→
   230→        // Get current HEAD as reference (no new work commit created)
   231→        let hash_output = match Command::new("git")
   232→            .args(["rev-parse", "HEAD"])
   233→            .output()
   234→        {
   235→            Ok(o) => o,
   236→            Err(e) => {
   237→                eprintln!("jjx_wrap: error: failed to get commit hash: {}", e);
   238→                return 1;
   239→            }
   240→        };
   241→
   242→        String::from_utf8_lossy(&hash_output.stdout).trim().to_string()
   243→    };
   244→
   245→    // Transition pace state to complete
   246→    let gallops_path = PathBuf::from(".claude/jjm/jjg_gallops.json");
   247→    let mut gallops = match Gallops::jjrg_load(&gallops_path) {
   248→        Ok(g) => g,
   249→        Err(e) => {
   250→            eprintln!("jjx_wrap: error loading Gallops: {}", e);
   251→            return 1;
   252→        }
   253→    };
   254→
   255→    let tally_args = LibTallyArgs {
   256→        coronet: args.coronet.clone(),
   257→        state: Some(jjrg_PaceState::Complete),
   258→        direction: None,
   259→        text: None,
   260→        silks: None,
   261→    };
   262→
   263→    if let Err(e) = gallops.jjrg_tally(tally_args) {
   264→        eprintln!("jjx_wrap: error: {}", e);
   265→        return 1;
   266→    }
   267→
   268→    // Save gallops
   269→    if let Err(e) = gallops.jjrg_save(&gallops_path) {
   270→        eprintln!("jjx_wrap: error saving Gallops: {}", e);
   271→        return 1;
   272→    }
   273→
   274→    // Create W chalk marker commit with gallops state change
   275→    let chalk_message = jjrn_format_chalk_message(&coronet, jjrn_ChalkMarker::Wrap, "pace complete");
   276→
   277→    let chalk_commit_args = vvc::vvcm_CommitArgs {
   278→        files: vec![".claude/jjm/jjg_gallops.json".to_string()],
   279→        message: chalk_message,
   280→        size_limit: vvc::VVCG_SIZE_LIMIT,
   281→        warn_limit: vvc::VVCG_WARN_LIMIT,
   282→    };
   283→
   284→    match vvc::machine_commit(&_lock, &chalk_commit_args) {
   285→        Ok(_) => {
   286→            println!("{}", commit_hash);
   287→            let fm = coronet.jjrf_parent_firemark();
   288→            let fm_key = fm.jjrf_display();
   289→            let fm_str = fm.jjrf_as_str();
   290→
   291→            // Lookahead: find next actionable pace in this heat
   292→            let next_pace_info = gallops.heats.get(&fm_key).and_then(|heat| {
   293→                heat.order.iter().find_map(|c| {
   294→                    heat.paces.get(c.as_str()).and_then(|pace| {
   295→                        pace.tacks.first().and_then(|tack| {
   296→                            match tack.state {
   297→                                jjrg_PaceState::Rough | jjrg_PaceState::Bridled => {
   298→                                    Some((c.clone(), tack.silks.clone()))
   299→                                }
   300→                                _ => None,
   301→                            }
   302→                        })
   303→                    })
   304→                })
   305→            });
   306→
   307→            eprintln!();
   308→            match next_pace_info {
   309→                Some((next_coronet, next_silks)) => {
   310→                    eprintln!("AGENT_RESPONSE: \u{20a2}{} wrapped. Next: {} (\u{20a2}{}) \u{2014} `/clear` then `/jjc-heat-mount {}`",
   311→                        args.coronet, next_silks, next_coronet, fm_str);
   312→                }
   313→                None => {
   314→                    eprintln!("AGENT_RESPONSE: \u{20a2}{} wrapped. All paces complete \u{2014} `/clear` then `/jjc-heat-retire {}`",
   315→                        args.coronet, fm_str);
   316→                }
   317→            }
   318→            0
   319→        }
   320→        Err(e) => {
   321→            eprintln!("jjx_wrap: error: chalk commit failed: {}", e);
   322→            eprintln!("jjx_wrap: warning: gallops state updated but not committed");
   323→            1
   324→        }
   325→    }
   326→    // lock released here
   327→}
